function JaguarsTile() {
  const [jaxGame, setJaxGame] = useState(null);
  const [jaxRecord, setJaxRecord] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchJaxSchedule() {
      try {
        // Sleeper NFL schedule endpoint
        const schedule = await fetchWithFallback(`https://api.sleeper.app/v1/schedule/nfl/regular/${NFL_SEASON}`);
        if (!schedule) { setLoading(false); return; }

        const now = new Date();
        // Determine current display week based on picks window
        // After Tuesday 3am: show upcoming game
        // Before Tuesday 3am: show most recent/current week
        const easternNow = new Date(now.toLocaleString("en-US", { timeZone: "America/New_York" }));
        const day = easternNow.getDay();
        const hour = easternNow.getHours();
        const showUpcoming = day > 2 || (day === 2 && hour >= 3) || day === 4;

        // Find JAX games
        const jaxGames = schedule.filter(g =>
          g.home_team === JAX_TEAM_ID || g.away_team === JAX_TEAM_ID
        ).sort((a, b) => new Date(a.date) - new Date(b.date));

        const upcoming = jaxGames.filter(g => new Date(g.date) > now);
        const past = jaxGames.filter(g => new Date(g.date) <= now);

        const targetGame = showUpcoming && upcoming.length > 0 ? upcoming[0] : past[past.length - 1] || upcoming[0];
        setJaxGame(targetGame || null);

        // Calculate record from past games
        let wins = 0, losses = 0, ties = 0;
        past.forEach(g => {
          if (!g.home_score && !g.away_score) return;
          const jaxScore = g.home_team === JAX_TEAM_ID ? g.home_score : g.away_score;
          const oppScore = g.home_team === JAX_TEAM_ID ? g.away_score : g.home_score;
          if (jaxScore > oppScore) wins++;
          else if (jaxScore < oppScore) losses++;
          else ties++;
        });
        setJaxRecord({ wins, losses, ties });
        setLoading(false);
      } catch(e) {
        console.warn("Jaguars schedule fetch failed:", e.message);
        setLoading(false);
      }
    }
    fetchJaxSchedule();
  }, []);

  if (loading) return (
    <div style={{ background: `${T.teal}18`, border: `1px solid ${T.teal}33`, borderRadius: 10, padding: "14px 20px", display: "flex", alignItems: "center", gap: 12 }}>
      <span style={{ fontSize: 24 }}>🐆</span>
      <span style={{ color: T.grayText, fontSize: 13 }}>Loading Jaguars schedule...</span>
    </div>
  );

  if (!jaxGame) return null;

  const isHome = jaxGame.home_team === JAX_TEAM_ID;
  const opponent = isHome ? jaxGame.away_team : jaxGame.home_team;
  const oppName = TEAM_NAMES[opponent] || opponent;
  const gameDate = new Date(jaxGame.date);
  const isPast = gameDate < new Date();
  const jaxScore = isHome ? jaxGame.home_score : jaxGame.away_score;
  const oppScore = isHome ? jaxGame.away_score : jaxGame.home_score;
  const recordStr = jaxRecord ? `${jaxRecord.wins}-${jaxRecord.losses}${jaxRecord.ties > 0 ? `-${jaxRecord.ties}` : ""}` : "—";

  // Format game time in ET
  const gameTimeStr = gameDate.toLocaleString("en-US", {
    timeZone: "America/New_York",
    weekday: "short", month: "short", day: "numeric",
    hour: "numeric", minute: "2-digit", hour12: true,
  });

  const jaxWon = isPast && jaxScore > oppScore;
  const jaxLost = isPast && jaxScore < oppScore;

  return (
    <div style={{
      background: "linear-gradient(135deg, #001f26 0%, #003840 100%)",
      border: `1px solid ${T.teal}`,
      borderRadius: 10, padding: "16px 20px",
      display: "flex", alignItems: "center", gap: 16, flexWrap: "wrap",
      boxShadow: `0 0 20px ${T.teal}22`,
    }}>
      {/* JAX side */}
      <div style={{ display: "flex", alignItems: "center", gap: 10, flex: 1, minWidth: 140 }}>
        <span style={{ fontSize: 32 }}>🐆</span>
        <div>
          <div style={{ fontWeight: 900, color: T.tealGlow, fontSize: 14 }}>Jacksonville Jaguars</div>
          <div style={{ fontSize: 12, color: T.goldLight, fontWeight: 700 }}>{recordStr} • {isHome ? "HOME" : "AWAY"}</div>
        </div>
      </div>

      {/* Score or VS */}
      <div style={{ textAlign: "center", minWidth: 80 }}>
        {isPast && jaxScore !== null && jaxScore !== undefined ? (
          <>
            <div style={{ display: "flex", gap: 8, alignItems: "center", justifyContent: "center" }}>
              <span style={{ fontSize: 26, fontWeight: 900, color: jaxWon ? T.goldLight : T.grayText }}>{jaxScore}</span>
              <span style={{ color: T.grayText, fontSize: 12 }}>–</span>
              <span style={{ fontSize: 26, fontWeight: 900, color: jaxLost ? T.goldLight : T.grayText }}>{oppScore}</span>
            </div>
            <div style={{ fontSize: 10, color: jaxWon ? T.tealGlow : "#ff6666", letterSpacing: 2, fontWeight: 700 }}>
              {jaxWon ? "WIN" : jaxLost ? "LOSS" : "TIE"}
            </div>
          </>
        ) : (
          <>
            <div style={{ fontSize: 13, fontWeight: 900, color: T.white }}>VS</div>
            <div style={{ fontSize: 10, color: T.grayText, letterSpacing: 1 }}>UPCOMING</div>
          </>
        )}
      </div>

      {/* Opponent side */}
      <div style={{ display: "flex", alignItems: "center", gap: 10, flex: 1, minWidth: 140, justifyContent: "flex-end" }}>
        <div style={{ textAlign: "right" }}>
          <div style={{ fontWeight: 900, color: T.white, fontSize: 14 }}>{oppName}</div>
          <div style={{ fontSize: 11, color: T.grayText }}>{gameTimeStr} ET</div>
        </div>
        <span style={{ fontSize: 32 }}>🏈</span>
      </div>
    </div>
  );
}

