// ── Firebase Auth helpers (no SDK — REST + Google Identity Services)
function GoogleSignIn({ onSignIn }) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleGoogleSignIn = () => {
    setLoading(true);
    setError(null);
    // Use Google Identity Services popup
    const client = window.google?.accounts?.oauth2?.initTokenClient({
      client_id: GOOGLE_CLIENT_ID,
      scope: "email profile",
      callback: async (resp) => {
        if (resp.error) { setError("Sign-in failed. Try again."); setLoading(false); return; }
        try {
          // Get user info from Google
          const r = await fetch("https://www.googleapis.com/oauth2/v3/userinfo", {
            headers: { Authorization: `Bearer ${resp.access_token}` }
          });
          const info = await r.json();
          onSignIn({ uid: info.sub, email: info.email, name: info.name, picture: info.picture, token: resp.access_token });
        } catch(e) { setError("Could not fetch profile. Try again."); }
        setLoading(false);
      }
    });
    client?.requestAccessToken() ?? (() => { setError("Google Sign-In not loaded yet. Refresh and try again."); setLoading(false); })();
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 12 }}>
      <button
        onClick={handleGoogleSignIn}
        disabled={loading}
        style={{
          display: "flex", alignItems: "center", gap: 12,
          background: T.white, color: "#333", border: "none",
          borderRadius: 8, padding: "12px 24px", fontSize: 15,
          fontWeight: 700, cursor: loading ? "not-allowed" : "pointer",
          boxShadow: "0 2px 8px rgba(0,0,0,0.3)", opacity: loading ? 0.7 : 1,
          transition: "all 0.15s",
        }}>
        <svg width="20" height="20" viewBox="0 0 48 48">
          <path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.72 17.74 9.5 24 9.5z"/>
          <path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/>
          <path fill="#FBBC05" d="M10.53 28.59c-.48-1.45-.76-2.99-.76-4.59s.27-3.14.76-4.59l-7.98-6.19C.92 16.46 0 20.12 0 24c0 3.88.92 7.54 2.56 10.78l7.97-6.19z"/>
          <path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.18 1.48-4.97 2.31-8.16 2.31-6.26 0-11.57-4.22-13.47-9.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"/>
        </svg>
        {loading ? "Signing in..." : "Sign in with Google"}
      </button>
      {error && <div style={{ color: "#ff6666", fontSize: 12 }}>{error}</div>}
    </div>
  );
}

function WeeklyPicks({ leagueData }) {
  const [googleUser, setGoogleUser] = useState(() => {
    try { const s = sessionStorage.getItem("jbff_guser"); return s ? JSON.parse(s) : null; } catch { return null; }
  });
  const [mappedTeam, setMappedTeam] = useState(null);
  const [claimedRosterIds, setClaimedRosterIds] = useState(new Set());
  const [loadingMap, setLoadingMap] = useState(false);
  const [picks, setPicks] = useState({});
  const [saving, setSaving] = useState(false);
  const [saveMsg, setSaveMsg] = useState(null);
  const [matchups, setMatchups] = useState(null);
  const [loadingMatchups, setLoadingMatchups] = useState(false);
  const [fbError, setFbError] = useState(false);
  const [scriptLoaded, setScriptLoaded] = useState(!!window.google?.accounts);
  const [picksOpen, setPicksOpen] = useState(isPicksWindowOpen());
  const [windowMsg, setWindowMsg] = useState(getPicksWindowMessage());

  // Re-check picks window every 30 seconds
  useEffect(() => {
    const interval = setInterval(() => {
      setPicksOpen(isPicksWindowOpen());
      setWindowMsg(getPicksWindowMessage());
    }, 30000);
    return () => clearInterval(interval);
  }, []);

  const standings = leagueData ? buildStandingsFromData(leagueData.rosters, leagueData.users) : [];
  const currentWeek = leagueData?.leagueInfo?.settings?.leg || 1;
  const leagueId = leagueData?.league?.league_id;

  // Load Google Identity Services script
  useEffect(() => {
    if (window.google?.accounts) { setScriptLoaded(true); return; }
    const script = document.createElement("script");
    script.src = "https://accounts.google.com/gsi/client";
    script.onload = () => setScriptLoaded(true);
    document.head.appendChild(script);
  }, []);

  // Fetch all claimed teams from Firebase on load
  useEffect(() => {
    if (!fbReady()) return;
    setLoadingMap(true);
    fbGet("usermap").then(data => {
      if (data) {
        const claimed = new Set(Object.values(data).map(v => v.rosterId).filter(Boolean));
        setClaimedRosterIds(claimed);
      }
      setLoadingMap(false);
    }).catch(() => setLoadingMap(false));
  }, []);

  // Persist Google user to session
  useEffect(() => {
    if (googleUser) {
      try { sessionStorage.setItem("jbff_guser", JSON.stringify(googleUser)); } catch {}
      // Look up team mapping in Firebase
      if (fbReady()) {
        fbGet(`usermap/${googleUser.uid}`).then(data => {
          if (data) setMappedTeam(data);
        });
      }
    }
  }, [googleUser]);

  // Load matchups
  useEffect(() => {
    if (!leagueId) return;
    setLoadingMatchups(true);
    sf(`/league/${leagueId}/matchups/${currentWeek}`)
      .then(data => { setMatchups(buildMatchupPairs(data, leagueData.rosters, leagueData.users)); setLoadingMatchups(false); })
      .catch(() => setLoadingMatchups(false));
  }, [leagueId, currentWeek]);

  // Load existing picks when mapped
  useEffect(() => {
    if (!googleUser || !fbReady()) return;
    fbGet(`week${currentWeek}/${googleUser.uid}`).then(d => { if (d) setPicks(d); });
  }, [googleUser, currentWeek]);

  const handlePick = (key, val) => { setPicks(p => ({ ...p, [key]: val })); setSaveMsg(null); };

  const handleSave = async () => {
    if (!fbReady()) { setFbError(true); return; }
    setSaving(true);
    const payload = {
      ...picks,
      submittedAt: new Date().toISOString(),
      googleUid: googleUser.uid,
      displayName: mappedTeam?.owner || googleUser.name,
      teamName: mappedTeam?.team || "Unregistered",
    };
    const ok = await fbSet(`week${currentWeek}/${googleUser.uid}`, payload);
    setSaving(false);
    if (ok) { setSaveMsg("saved"); setTimeout(() => setSaveMsg(null), 4000); }
    else setFbError(true);
  };

  const handleSignOut = () => {
    setGoogleUser(null);
    setMappedTeam(null);
    setPicks({});
    try { sessionStorage.removeItem("jbff_guser"); } catch {}
  };

  // Team claim — checks server-side that team isn't already taken
  const handleMapTeam = async (team) => {
    if (!googleUser || !fbReady()) return;
    // Re-fetch latest usermap to prevent race conditions
    const latest = await fbGet("usermap");
    const alreadyClaimed = latest
      ? Object.values(latest).some(v => v.rosterId === team.rosterId)
      : false;
    if (alreadyClaimed) {
      alert(`${team.team} has already been claimed by another user. Please select a different team or contact the commissioner.`);
      // Refresh claimed list
      const claimed = new Set(Object.values(latest).map(v => v.rosterId).filter(Boolean));
      setClaimedRosterIds(claimed);
      return;
    }
    const mapping = { owner: team.owner, team: team.team, rosterId: team.rosterId, googleUid: googleUser.uid, email: googleUser.email, claimedAt: new Date().toISOString() };
    await fbSet(`usermap/${googleUser.uid}`, mapping);
    setMappedTeam(mapping);
    setClaimedRosterIds(prev => new Set([...prev, team.rosterId]));
  };

  const upcomingMatchups = matchups ? matchups.filter(m => !m.complete) : [];
  const allPicked =
    upcomingMatchups.length > 0 &&
    upcomingMatchups.every(m => picks[`match_${m.matchupId}`]) &&
    picks.highestScore &&
    picks.lowestScore &&
    picks.biggestBlowout;

  if (!leagueData) return <Loading />;

  // ── Picks window closed
  const [weekPicks, setWeekPicks] = useState(null);
  const [loadingWeekPicks, setLoadingWeekPicks] = useState(false);

  useEffect(() => {
    if (!picksOpen && fbReady()) {
      setLoadingWeekPicks(true);
      fbGet(`week${currentWeek}`).then(data => {
        setWeekPicks(data);
        setLoadingWeekPicks(false);
      }).catch(() => setLoadingWeekPicks(false));
    }
  }, [picksOpen, currentWeek]);

  if (!picksOpen) {
    const submitted = weekPicks ? Object.values(weekPicks) : [];
    const submittedNames = new Set(submitted.map(p => p.displayName).filter(Boolean));
    const allTeams = standings;

    return (
      <div style={{ maxWidth: 1100, margin: "0 auto", padding: "36px 20px" }}>
        <div style={S.sectionTitle}>🎯 Weekly Picks — Week {currentWeek}</div>

        {/* Lock screen hero image */}
        <div style={{ borderRadius: 12, overflow: "hidden", marginBottom: 24, position: "relative", maxHeight: 340 }}>
          <img src={LOCK_SCREEN_IMG} alt="Lock Down The Bank" style={{ width: "100%", objectFit: "cover", objectPosition: "center 30%", maxHeight: 340, display: "block" }} />
          <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to bottom, transparent 40%, #0a0a0a 100%)" }} />
          <div style={{ position: "absolute", bottom: 20, left: 0, right: 0, textAlign: "center" }}>
            <div style={{ color: T.tealGlow, fontWeight: 700, fontSize: 14, letterSpacing: 3, textTransform: "uppercase" }}>{windowMsg}</div>
          </div>
        </div>

        {/* Picks submission checklist */}
        <div style={S.card}>
          <div style={{ background: "linear-gradient(90deg,#001f26,#003840)", padding: "12px 18px", borderBottom: `2px solid ${T.teal}`, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <span style={{ fontWeight: 900, color: T.tealGlow, fontSize: 14, letterSpacing: 2, textTransform: "uppercase" }}>
              Week {currentWeek} Submissions
            </span>
            <span style={{ color: T.grayText, fontSize: 12 }}>
              {submittedNames.size} of {allTeams.length} submitted
            </span>
          </div>
          {loadingWeekPicks ? (
            <div style={{ padding: 24, textAlign: "center", color: T.grayText, fontSize: 13 }}>Loading submissions...</div>
          ) : (
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 0 }}>
              {allTeams.map((t, i) => {
                const userPick = submitted.find(p => p.displayName === t.owner);
                const didSubmit = !!userPick;
                const ts = userPick?.submittedAt ? new Date(userPick.submittedAt) : null;
                const timeStr = ts ? ts.toLocaleString("en-US", { timeZone: "America/New_York", month: "short", day: "numeric", hour: "numeric", minute: "2-digit", hour12: true }) : null;
                return (
                  <div key={t.rosterId} style={{
                    display: "flex", alignItems: "center", gap: 14,
                    padding: "14px 18px",
                    borderBottom: `1px solid ${T.grayMid}`,
                    borderRight: i % 2 === 0 ? `1px solid ${T.grayMid}` : "none",
                    background: didSubmit ? `${T.teal}08` : "transparent",
                  }}>
                    <div style={{
                      width: 32, height: 32, borderRadius: "50%", flexShrink: 0,
                      background: didSubmit ? T.teal : T.grayMid,
                      display: "flex", alignItems: "center", justifyContent: "center",
                      fontSize: 16,
                    }}>
                      {didSubmit ? "✓" : "·"}
                    </div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontWeight: 700, color: didSubmit ? T.white : T.grayText, fontSize: 13, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                        {t.team}
                      </div>
                      <div style={{ fontSize: 11, color: didSubmit ? T.tealGlow : T.grayText, marginTop: 2 }}>
                        {didSubmit && timeStr ? `Submitted ${timeStr} ET` : "Not submitted"}
                      </div>
                    </div>
                    {didSubmit && <span style={S.badge("teal")}>✓ IN</span>}
                    {!didSubmit && <span style={{ ...S.badge("gold"), borderColor: T.grayMid, color: T.grayText, background: "transparent" }}>PENDING</span>}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    );
  }

  // ── Not signed in
  if (!googleUser) {
    return (
      <div style={S.section}>
        <div style={S.sectionTitle}>🎯 Weekly Picks — Week {currentWeek}</div>
        <div style={{ ...S.card, maxWidth: 420, padding: 36, margin: "0 auto", textAlign: "center" }}>
          <div style={{ fontSize: 44, marginBottom: 12 }}>🔐</div>
          <div style={{ fontWeight: 900, fontSize: 20, marginBottom: 8 }}>Sign In to Submit Picks</div>
          <div style={{ color: T.grayText, fontSize: 13, marginBottom: 28, lineHeight: 1.6 }}>
            Picks are tied to your Google account to ensure integrity. Only you can submit picks for your team.
          </div>
          {scriptLoaded
            ? <GoogleSignIn onSignIn={setGoogleUser} />
            : <div style={{ color: T.grayText, fontSize: 13 }}>Loading Google Sign-In...</div>
          }
        </div>
      </div>
    );
  }

  // ── Signed in but not mapped to a team yet
  if (!mappedTeam && !loadingMap) {
    const unclaimedTeams = standings.filter(t => !claimedRosterIds.has(t.rosterId));
    return (
      <div style={S.section}>
        <div style={S.sectionTitle}>🎯 Weekly Picks — Week {currentWeek}</div>
        <div style={{ ...S.card, maxWidth: 460, padding: 28, margin: "0 auto" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 20, padding: "12px 0", borderBottom: `1px solid ${T.grayMid}` }}>
            {googleUser.picture && <img src={googleUser.picture} alt="" style={{ width: 36, height: 36, borderRadius: "50%" }} />}
            <div>
              <div style={{ fontWeight: 700, color: T.white }}>{googleUser.name}</div>
              <div style={{ fontSize: 12, color: T.grayText }}>{googleUser.email}</div>
            </div>
            <button style={{ ...S.btn(false), marginLeft: "auto", fontSize: 11, padding: "4px 10px" }} onClick={handleSignOut}>Sign Out</button>
          </div>
          <div style={{ fontWeight: 700, color: T.white, fontSize: 15, marginBottom: 6 }}>Claim Your Fantasy Team</div>
          <div style={{ color: T.grayText, fontSize: 12, marginBottom: 6, lineHeight: 1.5 }}>
            Your Google account hasn't been linked to a team yet. Select your team below — <strong style={{ color: T.goldLight }}>each team can only be claimed once.</strong>
          </div>
          <div style={{ color: T.grayText, fontSize: 11, marginBottom: 18, lineHeight: 1.5, background: `${T.teal}18`, border: `1px solid ${T.teal}33`, borderRadius: 6, padding: "8px 12px" }}>
            ⚠️ Once claimed, your team is permanently linked to your Google account. If you claim the wrong team, contact the commissioner to fix it.
          </div>
          {unclaimedTeams.length === 0 ? (
            <div style={{ textAlign: "center", padding: 20, color: T.grayText, fontSize: 13 }}>
              All teams have been claimed. If this is an error, contact the commissioner.
            </div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {unclaimedTeams.map(t => (
                <button key={t.rosterId}
                  style={{ ...S.btn(false), width: "100%", padding: "11px 16px", fontSize: 13, textAlign: "left" }}
                  onClick={() => handleMapTeam(t)}>
                  <span style={{ color: T.tealGlow, fontWeight: 900 }}>{t.team}</span>
                  <span style={{ color: T.grayText, marginLeft: 8 }}>({t.owner})</span>
                </button>
              ))}
            </div>
          )}
          {standings.filter(t => claimedRosterIds.has(t.rosterId)).length > 0 && (
            <div style={{ marginTop: 16, borderTop: `1px solid ${T.grayMid}`, paddingTop: 14 }}>
              <div style={{ fontSize: 11, color: T.grayText, letterSpacing: 1, textTransform: "uppercase", marginBottom: 8 }}>Already Claimed</div>
              {standings.filter(t => claimedRosterIds.has(t.rosterId)).map(t => (
                <div key={t.rosterId} style={{ display: "flex", justifyContent: "space-between", padding: "7px 0", borderBottom: `1px solid ${T.grayMid}22` }}>
                  <span style={{ color: T.grayText, fontSize: 12, fontWeight: 700 }}>{t.team}</span>
                  <span style={{ ...S.badge("teal"), fontSize: 10 }}>✓ CLAIMED</span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    );
  }

  if (loadingMap) return <Loading msg="Checking team registrations..." />;

  // ── Signed in and mapped — show picks form
  return (
    <div style={S.section}>
      <div style={S.sectionTitle}>🎯 Weekly Picks — Week {currentWeek}</div>

      {/* Picks window countdown banner */}
      <div style={{ background: `${T.teal}18`, border: `1px solid ${T.teal}44`, borderRadius: 8, padding: "10px 16px", marginBottom: 14, fontSize: 13, color: T.tealGlow, fontWeight: 600 }}>
        {windowMsg}
      </div>

      {/* User header */}
      <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 20, background: T.gray, border: `1px solid ${T.grayMid}`, borderRadius: 8, padding: "12px 18px" }}>
        {googleUser.picture && <img src={googleUser.picture} alt="" style={{ width: 32, height: 32, borderRadius: "50%" }} />}
        <div style={{ flex: 1 }}>
          <span style={{ fontWeight: 700, color: T.tealGlow }}>{mappedTeam.team}</span>
          <span style={{ color: T.grayText, fontSize: 12, marginLeft: 8 }}>({mappedTeam.owner})</span>
        </div>
        <button style={{ ...S.btn(false), fontSize: 11, padding: "4px 10px" }} onClick={handleSignOut}>Sign Out</button>
      </div>

      {!fbReady() && <div style={{ background: "#1a1000", border: "1px solid #664400", borderRadius: 8, padding: 12, marginBottom: 18, fontSize: 12, color: "#ffaa44" }}>⚠️ Firebase not configured — picks won't save. See Setup Guide tab.</div>}
      {loadingMatchups && <Loading msg="Loading matchups..." />}

      {/* ── Matchup Winner Picks */}
      {upcomingMatchups.length > 0 && (
        <div style={{ marginBottom: 28 }}>
          <div style={{ fontWeight: 700, color: T.white, fontSize: 13, marginBottom: 12, letterSpacing: 1, textTransform: "uppercase" }}>
            🏆 Pick the Winner — All 6 Matchups
          </div>
          {upcomingMatchups.map((m, idx) => (
            <div key={m.matchupId} style={S.pickCard}>
              <div style={S.pickHeader}>
                <span style={{ color: T.tealGlow, fontSize: 11, letterSpacing: 2 }}>MATCHUP {idx + 1}</span>
                {picks[`match_${m.matchupId}`] && <span style={S.badge("teal")}>✓ PICKED</span>}
              </div>
              <div style={{ padding: "12px 16px", display: "flex", alignItems: "center", gap: 10 }}>
                <button
                  style={{ ...S.btn(picks[`match_${m.matchupId}`] === m.home.rosterId), flex: 1, padding: "12px 8px", textAlign: "center" }}
                  onClick={() => handlePick(`match_${m.matchupId}`, m.home.rosterId)}>
                  <div style={{ fontWeight: 900, fontSize: 13 }}>{m.home.team}</div>
                  <div style={{ fontSize: 11, opacity: 0.7 }}>{m.home.owner}</div>
                </button>
                <div style={{ textAlign: "center", minWidth: 36 }}>
                  <div style={{ color: T.grayText, fontWeight: 900, fontSize: 12 }}>VS</div>
                </div>
                <button
                  style={{ ...S.btn(picks[`match_${m.matchupId}`] === m.away.rosterId), flex: 1, padding: "12px 8px", textAlign: "center" }}
                  onClick={() => handlePick(`match_${m.matchupId}`, m.away.rosterId)}>
                  <div style={{ fontWeight: 900, fontSize: 13 }}>{m.away.team}</div>
                  <div style={{ fontSize: 11, opacity: 0.7 }}>{m.away.owner}</div>
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {upcomingMatchups.length === 0 && !loadingMatchups && (
        <div style={{ ...S.card, padding: 24, textAlign: "center", color: T.grayText, marginBottom: 28 }}>
          No upcoming matchups found for Week {currentWeek}. Scores may still be in progress.
        </div>
      )}

      {/* ── Special Picks */}
      <div style={{ fontWeight: 700, color: T.white, fontSize: 13, marginBottom: 12, letterSpacing: 1, textTransform: "uppercase" }}>
        ⭐ Special Picks
      </div>

      {/* Highest Score */}
      <div style={{ ...S.pickCard, marginBottom: 10 }}>
        <div style={S.pickHeader}>
          <span style={{ color: T.goldLight, fontSize: 12, fontWeight: 700 }}>🔥 Highest Score This Week</span>
          {picks.highestScore !== undefined && <span style={S.badge("teal")}>✓ PICKED</span>}
        </div>
        <div style={{ padding: "12px 16px", display: "flex", flexWrap: "wrap", gap: 7 }}>
          {standings.map(t => (
            <button key={t.rosterId} style={S.btn(picks.highestScore === t.rosterId)}
              onClick={() => handlePick("highestScore", t.rosterId)}>
              {t.team}
            </button>
          ))}
        </div>
      </div>

      {/* Lowest Score */}
      <div style={{ ...S.pickCard, marginBottom: 10 }}>
        <div style={S.pickHeader}>
          <span style={{ color: T.goldLight, fontSize: 12, fontWeight: 700 }}>💩 Lowest Score This Week</span>
          {picks.lowestScore !== undefined && <span style={S.badge("teal")}>✓ PICKED</span>}
        </div>
        <div style={{ padding: "12px 16px", display: "flex", flexWrap: "wrap", gap: 7 }}>
          {standings.map(t => (
            <button key={t.rosterId} style={S.btn(picks.lowestScore === t.rosterId)}
              onClick={() => handlePick("lowestScore", t.rosterId)}>
              {t.team}
            </button>
          ))}
        </div>
      </div>

      {/* Biggest Blowout — pick from the 6 live matchups */}
      <div style={{ ...S.pickCard, marginBottom: 10 }}>
        <div style={S.pickHeader}>
          <span style={{ color: T.goldLight, fontSize: 12, fontWeight: 700 }}>💥 Biggest Blowout Matchup</span>
          {picks.biggestBlowout !== undefined && <span style={S.badge("teal")}>✓ PICKED</span>}
        </div>
        <div style={{ padding: "12px 16px", display: "flex", flexWrap: "wrap", gap: 7 }}>
          {upcomingMatchups.length > 0
            ? upcomingMatchups.map((m, idx) => (
                <button key={m.matchupId}
                  style={{ ...S.btn(picks.biggestBlowout === m.matchupId), minWidth: 160 }}
                  onClick={() => handlePick("biggestBlowout", m.matchupId)}>
                  <div style={{ fontWeight: 700, fontSize: 12 }}>Matchup {idx + 1}</div>
                  <div style={{ fontSize: 11, opacity: 0.75 }}>{m.home.owner} vs {m.away.owner}</div>
                </button>
              ))
            : <div style={{ color: T.grayText, fontSize: 12 }}>Matchups loading...</div>
          }
        </div>
      </div>

      {/* Submit */}
      <div style={{ marginTop: 22, display: "flex", alignItems: "center", gap: 14, flexWrap: "wrap" }}>
        <button
          style={{ ...S.btn(true), padding: "12px 32px", fontSize: 14, opacity: allPicked ? 1 : 0.5, cursor: allPicked ? "pointer" : "not-allowed" }}
          onClick={handleSave}
          disabled={!allPicked || saving}>
          {saving ? "Saving..." : "Submit Picks"}
        </button>
        {!allPicked && <span style={{ color: T.grayText, fontSize: 12 }}>Complete all picks above to submit</span>}
        {saveMsg === "saved" && <span style={{ color: T.tealGlow, fontWeight: 700, fontSize: 13 }}>✓ Picks saved for Week {currentWeek}!</span>}
        {fbError && <span style={{ color: "#ff6666", fontSize: 12 }}>Save failed — check Firebase config</span>}
      </div>
    </div>
  );
}

// ─── PICK LEADERBOARD TAB ────────────────────────────────────────────────────
function PickLeaderboard({ leagueData }) {
  const [allPicks, setAllPicks] = useState(null);
  const [loading, setLoading] = useState(true);
  const currentWeek = leagueData?.leagueInfo?.settings?.leg || 1;

  useEffect(() => {
    if (!fbReady()) { setLoading(false); return; }
    fbGet("").then(d => { setAllPicks(d); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  if (!leagueData) return <Loading />;
  if (!fbReady()) return (
    <div style={S.section}>
      <div style={S.sectionTitle}>📊 Pick Accuracy — Season Rankings</div>
      <div style={{ ...S.card, padding: 28, textAlign: "center", color: T.grayText }}>
        <div style={{ fontSize: 34, marginBottom: 10 }}>🔧</div>
        <div style={{ fontWeight: 700, color: T.white, marginBottom: 6 }}>Firebase Not Connected</div>
        <div style={{ fontSize: 13 }}>See the <strong style={{ color: T.tealGlow }}>Setup Guide</strong> tab to enable pick tracking.</div>
      </div>
    </div>
  );
  if (loading) return <Loading msg="Loading pick history..." />;
  const standings = buildStandingsFromData(leagueData.rosters, leagueData.users);
  const leaderboard = standings.map(t => {
    let correct = 0, total = 0;
    if (allPicks) {
      Object.values(allPicks).forEach(weekData => {
        const key = t.owner.replace(/\s+/g, "_");
        if (weekData[key]) {
          const p = weekData[key];
          const pickKeys = Object.keys(p).filter(k => k.startsWith("match_") || ["highestScore","lowestScore","biggestBlowout"].includes(k));
          total += pickKeys.length;
        }
      });
    }
    return { ...t, correct, total };
  });
  return (
    <div style={S.section}>
      <div style={S.sectionTitle}>📊 Pick Accuracy — Season Rankings</div>
      <div style={{ color: T.grayText, fontSize: 12, marginBottom: 14 }}>Pick grading is updated by the commissioner in Firebase after each week's games complete.</div>
      <div style={S.card}>
        {leaderboard.map((p, i) => (
          <div key={p.rosterId} style={{ display: "flex", alignItems: "center", gap: 14, padding: "13px 18px", borderBottom: `1px solid ${T.grayMid}`, background: i === 0 ? `${T.gold}11` : i === 1 ? `${T.teal}0a` : "transparent" }}>
            <div style={S.rankBadge(i)}>{i + 1}</div>
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 700, color: i < 3 ? T.white : T.grayText }}>{p.team}</div>
              <div style={{ fontSize: 11, color: T.grayText }}>{p.owner}</div>
            </div>
            <div style={{ textAlign: "right" }}>
              <div style={{ fontWeight: 900, color: T.tealGlow, fontSize: 18 }}>{p.total > 0 ? `${p.correct}/${p.total}` : "—"}</div>
              <div style={{ fontSize: 10, color: T.grayText }}>CORRECT PICKS</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}


// ─── JAGUARS GAME TILE ────────────────────────────────────────────────────────
function JaguarsGameTile({ season }) {
  const [gameData, setGameData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getJaguarsSchedule(season).then(data => {
      setGameData(data);
      setLoading(false);
    });
  }, [season]);

  if (loading) return (
    <div style={{ background: T.gray, border: `1px solid ${T.grayMid}`, borderRadius: 8, padding: "16px 20px", display: "flex", alignItems: "center", gap: 12 }}>
      <div style={S.spinner} />
      <span style={{ color: T.grayText, fontSize: 12 }}>Loading Jaguars schedule...</span>
    </div>
  );

  if (!gameData || !gameData.game) return (
    <div style={{ background: T.gray, border: `1px solid ${T.grayMid}`, borderRadius: 8, padding: "16px 20px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <span style={{ fontSize: 22 }}>🐆</span>
        <div>
          <div style={{ fontWeight: 700, color: T.white, fontSize: 14 }}>Jacksonville Jaguars</div>
          <div style={{ color: T.grayText, fontSize: 12 }}>Schedule unavailable for Week {gameData?.week || "?"}</div>
        </div>
      </div>
    </div>
  );

  const { game, week, jaxRecord, oppRecord, oppId } = gameData;
  const isHome = game.home_team === JAX_TEAM_ID;
  const gameDate = game.date ? new Date(game.date) : null;
  const gameTime = gameDate ? gameDate.toLocaleString("en-US", {
    weekday: "short", month: "short", day: "numeric",
    hour: "numeric", minute: "2-digit", timeZone: "America/New_York",
    timeZoneName: "short"
  }) : "Time TBD";

  const jaxW = jaxRecord?.wins ?? "?";
  const jaxL = jaxRecord?.losses ?? "?";
  const oppW = oppRecord?.wins ?? "?";
  const oppL = oppRecord?.losses ?? "?";
  const oppName = NFL_TEAMS[oppId] || oppId || "TBD";

  return (
    <div style={{
      background: "linear-gradient(135deg, #001a1f 0%, #003840 100%)",
      border: `1px solid ${T.teal}`,
      borderRadius: 8,
      padding: "14px 18px",
      boxShadow: `0 0 20px ${T.teal}22`,
    }}>
      {/* Header */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
        <div style={{ fontSize: 10, color: T.tealGlow, letterSpacing: 2, textTransform: "uppercase", fontWeight: 700 }}>
          🐆 NFL Week {week}
        </div>
        <div style={{ fontSize: 10, color: T.grayText, letterSpacing: 1 }}>
          {isHome ? "HOME" : "AWAY"}
        </div>
      </div>

      {/* Matchup */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 8 }}>
        {/* JAX */}
        <div style={{ flex: 1, textAlign: isHome ? "left" : "right" }}>
          <div style={{ fontWeight: 900, fontSize: 15, color: T.tealGlow }}>Jacksonville</div>
          <div style={{ fontWeight: 900, fontSize: 15, color: T.white }}>Jaguars</div>
          <div style={{ fontSize: 12, color: T.goldLight, fontWeight: 700, marginTop: 2 }}>{jaxW}–{jaxL}</div>
        </div>

        {/* VS */}
        <div style={{ textAlign: "center", padding: "0 8px" }}>
          <div style={{ fontSize: 11, color: T.grayText, fontWeight: 900, letterSpacing: 2 }}>
            {isHome ? "VS" : "@"}
          </div>
          <div style={{ fontSize: 9, color: T.grayText, marginTop: 4, letterSpacing: 1 }}>{gameTime}</div>
        </div>

        {/* Opponent */}
        <div style={{ flex: 1, textAlign: isHome ? "right" : "left" }}>
          <div style={{ fontWeight: 900, fontSize: 15, color: T.white }}>
            {oppName.split(" ").slice(0, -1).join(" ")}
          </div>
          <div style={{ fontWeight: 900, fontSize: 15, color: T.white }}>
            {oppName.split(" ").slice(-1)[0]}
          </div>
          <div style={{ fontSize: 12, color: T.grayText, fontWeight: 700, marginTop: 2 }}>{oppW}–{oppL}</div>
        </div>
      </div>
    </div>
  );
}

// ─── LEAGUE HISTORY TAB ──────────────────────────────────────────────────────
function LeagueHistory({ leagueData }) {
  const [seasons, setSeasons] = useState(null);
  const [loading, setLoading] = useState(true);
  const [loadingMsg, setLoadingMsg] = useState("Fetching league history...");
  const [error, setError] = useState(null);
  const [selectedYear, setSelectedYear] = useState(null);
  const [pointsData, setPointsData] = useState(null);
  const [loadingPoints, setLoadingPoints] = useState(false);

  useEffect(() => {
    if (!leagueData) return;
    setLoading(true);
    async function fetchHistory() {
      try {
        setLoadingMsg("Walking season history via Sleeper...");
        console.log("[LeagueHistory] Starting fetch. leagueInfo:", JSON.stringify(leagueData.leagueInfo?.league_id), "season:", leagueData.leagueInfo?.season, "prev_id:", leagueData.leagueInfo?.previous_league_id);
        const historicalSeasons = await getAllHistoricalLeagues(leagueData.leagueInfo, LEAGUE_START_YEAR);
        console.log("[LeagueHistory] Got seasons:", historicalSeasons.map(s => s.year));
        setSeasons(historicalSeasons);
        if (historicalSeasons.length > 0) setSelectedYear(historicalSeasons[historicalSeasons.length - 1].year);
        setLoading(false);
        setLoadingPoints(true);
        const ownerPoints = {};
        const completedSeasons = historicalSeasons.filter(s => s.info.status === "complete");
        for (const season of completedSeasons) {
          const userMap = {};
          season.users.forEach(u => { userMap[u.user_id] = u; });
          season.rosters.forEach(r => {
            const user = userMap[r.owner_id] || {};
            const name = user.display_name || "Unknown";
            const pts = (r.settings?.fpts || 0) + (r.settings?.fpts_decimal || 0) / 100;
            ownerPoints[name] = (ownerPoints[name] || 0) + pts;
          });
        }
        // Add current season
        const curUserMap = {};
        leagueData.users.forEach(u => { curUserMap[u.user_id] = u; });
        leagueData.rosters.forEach(r => {
          const user = curUserMap[r.owner_id] || {};
          const name = user.display_name || "Unknown";
          const pts = (r.settings?.fpts || 0) + (r.settings?.fpts_decimal || 0) / 100;
          ownerPoints[name] = (ownerPoints[name] || 0) + pts;
        });
        setPointsData(ownerPoints);
        setLoadingPoints(false);
      } catch (e) {
        console.error("[LeagueHistory] Fatal error:", e.message, e.stack);
        setError(e.message + " — Check browser console (F12) for details.");
        setLoading(false);
        setLoadingPoints(false);
      }
    }
    fetchHistory();
  }, [leagueData]);

  if (!leagueData) return <Loading />;
  if (loading) return <Loading msg={loadingMsg} />;
  if (error) return <ErrBox msg={`History fetch error: ${error}`} />;
  if (!seasons || seasons.length === 0) return <ErrBox msg="No historical seasons found." />;

  // ── Build all summaries safely
  let sleeperSummaries = [], espnSummaries = [], allSeasonSummaries = [];
  let championRecord = {}, sackoRecord = {}, allTimeRecords = [];
  let allTimeLeaderboard = [];

  try {
    sleeperSummaries = (seasons || []).map(s => {
      try {
        const standings = buildStandingsFromData(s.rosters || [], s.users || []);
        const champ = findChampion(s.winnersBracket, s.rosters, s.users, standings);
        const sacko = standings.length > 0 ? standings[standings.length - 1] : null;
        return { year: s.year, standings, champ, sacko, status: s.info?.status || "complete", source: "sleeper" };
      } catch(e) {
        console.warn("[LeagueHistory] Error processing season", s.year, e.message);
        return { year: s.year, standings: [], champ: null, sacko: null, status: "complete", source: "sleeper" };
      }
    });
  } catch(e) { console.error("[LeagueHistory] sleeperSummaries failed:", e.message); }

  try {
    espnSummaries = (ESPN_HISTORY || []).map(e => ({
      year: e.year,
      standings: [],
      champ: e.champion ? { owner: e.champion, team: e.champion } : null,
      sacko: e.sacko ? { owner: e.sacko, team: e.sacko } : null,
      status: "complete",
      source: "espn",
    }));
  } catch(e) { console.error("[LeagueHistory] espnSummaries failed:", e.message); }

  try {
    allSeasonSummaries = [...espnSummaries, ...sleeperSummaries].sort((a, b) => a.year - b.year);
  } catch(e) { console.error("[LeagueHistory] allSeasonSummaries failed:", e.message); }

  try {
    allSeasonSummaries.forEach(s => {
      if (s.status !== "complete") return;
      if (s.champ?.owner) championRecord[s.champ.owner] = (championRecord[s.champ.owner] || 0) + 1;
      if (s.sacko?.owner) sackoRecord[s.sacko.owner] = (sackoRecord[s.sacko.owner] || 0) + 1;
    });
  } catch(e) { console.error("[LeagueHistory] champion/sacko record failed:", e.message); }

  try {
    const allTimeRecordsMap = {};
    sleeperSummaries.forEach(s => {
      (s.standings || []).forEach(t => {
        if (!t?.owner) return;
        if (!allTimeRecordsMap[t.owner]) allTimeRecordsMap[t.owner] = { wins: 0, losses: 0, ties: 0 };
        allTimeRecordsMap[t.owner].wins += (t.wins || 0);
        allTimeRecordsMap[t.owner].losses += (t.losses || 0);
        allTimeRecordsMap[t.owner].ties += (t.ties || 0);
      });
    });
    allTimeLeaderboard = Object.entries(allTimeRecordsMap)
      .map(([owner, r]) => ({ owner, ...r, pct: r.wins / Math.max(r.wins + r.losses + r.ties, 1) }))
      .sort((a, b) => b.pct - a.pct || b.wins - a.wins);
  } catch(e) { console.error("[LeagueHistory] allTimeLeaderboard failed:", e.message); }

  const selectedSeason = allSeasonSummaries.find(s => s.year === selectedYear) || null;
  let pointsLeaderboard = [], maxPts = 1, maxWins = 1;
  try {
    pointsLeaderboard = pointsData
      ? Object.entries(pointsData).sort((a, b) => b[1] - a[1]).map(([owner, pts]) => ({ owner, pts }))
      : [];
    maxPts = pointsLeaderboard.length > 0 ? pointsLeaderboard[0].pts : 1;
    maxWins = allTimeLeaderboard.length > 0 ? allTimeLeaderboard[0].wins : 1;
  } catch(e) { console.error("[LeagueHistory] points calc failed:", e.message); }

  return (
    <div style={S.section}>
      <div style={S.sectionTitle}>📜 League History — {ESPN_START_YEAR}–Present</div>

      {/* ── Champion & Sacko Hall of Fame ── */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 32 }}>
        <div style={S.card}>
          <div style={{ background: "linear-gradient(90deg,#1a1200,#2a1e00)", padding: "12px 18px", borderBottom: `2px solid ${T.gold}`, display: "flex", alignItems: "center", gap: 8 }}>
            <span style={{ fontSize: 20 }}>🏆</span>
            <span style={{ fontWeight: 900, color: T.goldLight, fontSize: 14, letterSpacing: 2, textTransform: "uppercase" }}>Championship Record</span>
            <span style={{ marginLeft: "auto", fontSize: 10, color: T.grayText, letterSpacing: 1 }}>{ESPN_START_YEAR}–PRESENT</span>
          </div>
          {Object.entries(championRecord).length === 0
            ? <div style={{ padding: 20, color: T.grayText, fontSize: 13 }}>No completed seasons yet</div>
            : Object.entries(championRecord).sort((a, b) => b[1] - a[1]).map(([owner, count]) => (
              <div key={owner} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "12px 18px", borderBottom: `1px solid ${T.grayMid}` }}>
                <div style={{ fontWeight: 700, color: T.white }}>{owner}</div>
                <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                  {Array.from({ length: Math.min(count, 5) }).map((_, i) => <span key={i} style={{ fontSize: 16 }}>🏆</span>)}
                  <span style={{ ...S.badge("gold"), marginLeft: 4 }}>{count}x</span>
                </div>
              </div>
            ))
          }
        </div>

        <div style={S.card}>
          <div style={{ background: "linear-gradient(90deg,#1a0000,#2a0a0a)", padding: "12px 18px", borderBottom: `2px solid #660000`, display: "flex", alignItems: "center", gap: 8 }}>
            <span style={{ fontSize: 20 }}>💩</span>
            <span style={{ fontWeight: 900, color: "#ff6666", fontSize: 14, letterSpacing: 2, textTransform: "uppercase" }}>Sacko Record</span>
            <span style={{ marginLeft: "auto", fontSize: 10, color: T.grayText, letterSpacing: 1 }}>{ESPN_START_YEAR}–PRESENT</span>
          </div>
          {Object.entries(sackoRecord).length === 0
            ? <div style={{ padding: 20, color: T.grayText, fontSize: 13 }}>No Sacko records found</div>
            : Object.entries(sackoRecord).sort((a, b) => b[1] - a[1]).map(([owner, count]) => (
              <div key={owner} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "12px 18px", borderBottom: `1px solid ${T.grayMid}` }}>
                <div style={{ fontWeight: 700, color: T.white }}>{owner}</div>
                <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                  {Array.from({ length: Math.min(count, 5) }).map((_, i) => <span key={i} style={{ fontSize: 16 }}>💩</span>)}
                  <span style={{ ...S.badge("red"), marginLeft: 4 }}>{count}x</span>
                </div>
              </div>
            ))
          }
        </div>
      </div>

      {/* ── All-Time W/L Records (Sleeper seasons only) ── */}
      <div style={{ marginBottom: 32 }}>
        <div style={{ fontWeight: 900, color: T.white, fontSize: 15, letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>
          All-Time Win/Loss Record
        </div>
        <div style={{ color: T.grayText, fontSize: 12, marginBottom: 14 }}>
          Aggregate regular season record across all Sleeper seasons ({LEAGUE_START_YEAR}–present). ESPN seasons excluded — game-by-game data unavailable.
        </div>
        <div style={S.card}>
          <table style={S.table}>
            <thead><tr>
              <th style={S.th}>#</th>
              <th style={S.th}>Owner</th>
              <th style={S.thR}>W</th>
              <th style={S.thR}>L</th>
              <th style={S.thR}>T</th>
              <th style={S.thR}>WIN%</th>
              <th style={{ ...S.thR, minWidth: 120 }}>ALL-TIME RECORD</th>
            </tr></thead>
            <tbody>
              {allTimeLeaderboard.map((p, i) => (
                <tr key={p.owner} style={{ background: i % 2 === 0 ? "#181818" : "transparent" }}>
                  <td style={S.td}><span style={S.rankBadge(i)}>{i + 1}</span></td>
                  <td style={{ ...S.td, fontWeight: 700, color: i === 0 ? T.goldLight : T.white }}>{p.owner}</td>
                  <td style={{ ...S.tdR, color: T.goldLight, fontWeight: 700 }}>{p.wins}</td>
                  <td style={{ ...S.tdR, color: T.grayText }}>{p.losses}</td>
                  <td style={{ ...S.tdR, color: T.grayText }}>{p.ties}</td>
                  <td style={{ ...S.tdR, color: T.tealGlow, fontWeight: 700 }}>{(p.pct * 100).toFixed(1)}%</td>
                  <td style={S.tdR}>
                    <div style={{ background: T.grayMid, borderRadius: 4, height: 6, overflow: "hidden", minWidth: 100 }}>
                      <div style={{ width: `${(p.wins / maxWins) * 100}%`, height: "100%", borderRadius: 4, background: `linear-gradient(90deg,${T.teal},${T.tealGlow})` }} />
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* ── Year-by-Year Final Standings ── */}
      <div style={{ marginBottom: 32 }}>
        <div style={{ fontWeight: 900, color: T.white, fontSize: 15, letterSpacing: 2, textTransform: "uppercase", marginBottom: 14 }}>
          Final Standings by Season
        </div>
        <div style={{ display: "flex", gap: 8, marginBottom: 18, flexWrap: "wrap" }}>
          {allSeasonSummaries.map(s => (
            <button key={s.year} style={{ ...S.btn(selectedYear === s.year), position: "relative" }} onClick={() => setSelectedYear(s.year)}>
              {s.year}
              {s.source === "espn" && <span style={{ fontSize: 8, color: T.gold, marginLeft: 4 }}>ESPN</span>}
              {s.status !== "complete" && s.source !== "espn" && <span style={{ fontSize: 8, color: T.tealGlow, marginLeft: 4 }}>LIVE</span>}
            </button>
          ))}
        </div>

        {selectedSeason && (
          <div style={S.card}>
            <div style={{ background: "linear-gradient(90deg,#001f26,#003840)", padding: "12px 18px", borderBottom: `2px solid ${T.teal}`, display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 8 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <span style={{ fontWeight: 900, color: T.tealGlow, letterSpacing: 2 }}>{selectedSeason.year} SEASON</span>
                {selectedSeason.source === "espn" && <span style={{ ...S.badge("gold") }}>ESPN ERA</span>}
                {selectedSeason.status !== "complete" && <span style={S.badge("teal")}>IN PROGRESS</span>}
              </div>
              <div style={{ display: "flex", gap: 16, flexWrap: "wrap" }}>
                {selectedSeason.champ && <span style={{ color: T.goldLight, fontSize: 12 }}>🏆 <strong>{selectedSeason.champ.owner}</strong></span>}
                {selectedSeason.sacko && <span style={{ color: "#ff6666", fontSize: 12 }}>💩 <strong>{selectedSeason.sacko.owner}</strong></span>}
                {!selectedSeason.sacko && <span style={{ color: T.grayText, fontSize: 12 }}>💩 Sacko: no record</span>}
              </div>
            </div>

            {selectedSeason.source === "espn" ? (
              <div style={{ padding: "24px 20px", textAlign: "center", color: T.grayText }}>
                <div style={{ fontSize: 28, marginBottom: 10 }}>📺</div>
                <div style={{ fontWeight: 700, color: T.white, marginBottom: 6 }}>ESPN Era — {selectedSeason.year}</div>
                <div style={{ fontSize: 13, marginBottom: 16 }}>Full standings data unavailable for ESPN seasons. Only champion and Sacko records were carried over.</div>
                <div style={{ display: "flex", justifyContent: "center", gap: 32 }}>
                  {selectedSeason.champ && (
                    <div style={{ textAlign: "center" }}>
                      <div style={{ fontSize: 32 }}>🏆</div>
                      <div style={{ fontWeight: 900, color: T.goldLight, fontSize: 16 }}>{selectedSeason.champ.owner}</div>
                      <div style={{ fontSize: 11, color: T.grayText, letterSpacing: 1 }}>CHAMPION</div>
                    </div>
                  )}
                  {selectedSeason.sacko && (
                    <div style={{ textAlign: "center" }}>
                      <div style={{ fontSize: 32 }}>💩</div>
                      <div style={{ fontWeight: 900, color: "#ff6666", fontSize: 16 }}>{selectedSeason.sacko.owner}</div>
                      <div style={{ fontSize: 11, color: T.grayText, letterSpacing: 1 }}>SACKO</div>
                    </div>
                  )}
                </div>
              </div>
            ) : (
              <table style={S.table}>
                <thead><tr>
                  <th style={S.th}>Place</th><th style={S.th}>Team</th><th style={S.th}>Owner</th>
                  <th style={S.thR}>W</th><th style={S.thR}>L</th><th style={S.thR}>PTS</th><th style={S.thR}>Award</th>
                </tr></thead>
                <tbody>
                  {selectedSeason.standings.map((t, i) => {
                    const isChamp = selectedSeason.champ?.owner === t.owner && selectedSeason.status === "complete";
                    const isSacko = i === selectedSeason.standings.length - 1 && selectedSeason.status === "complete";
                    return (
                      <tr key={t.rosterId} style={{ background: i % 2 === 0 ? "#181818" : "transparent" }}>
                        <td style={S.td}><span style={S.rankBadge(i)}>{i + 1}</span></td>
                        <td style={S.td}><span style={{ fontWeight: 700, color: isChamp ? T.goldLight : isSacko ? "#ff6666" : T.white }}>{t.team}</span></td>
                        <td style={{ ...S.td, color: T.grayText }}>{t.owner}</td>
                        <td style={{ ...S.tdR, color: T.goldLight, fontWeight: 700 }}>{t.wins}</td>
                        <td style={{ ...S.tdR, color: T.grayText }}>{t.losses}</td>
                        <td style={S.tdR}>{t.pts.toFixed(2)}</td>
                        <td style={S.tdR}>
                          {isChamp && <span style={S.badge("gold")}>🏆 CHAMP</span>}
                          {isSacko && <span style={S.badge("red")}>💩 SACKO</span>}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            )}
          </div>
        )}
      </div>

      {/* ── All-Time Points Leaderboard ── */}
      <div>
        <div style={{ fontWeight: 900, color: T.white, fontSize: 15, letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>
          All-Time Points Scored
        </div>
        <div style={{ color: T.grayText, fontSize: 12, marginBottom: 16 }}>
          Cumulative fantasy points from {LEAGUE_START_YEAR} (Sleeper era) through current week. Updates automatically as weekly scores finalize.
        </div>
        {loadingPoints && <Loading msg="Calculating all-time totals..." />}
        {!loadingPoints && pointsLeaderboard.length > 0 && (
          <div style={S.card}>
            {pointsLeaderboard.map((p, i) => (
              <div key={p.owner} style={{ padding: "14px 18px", borderBottom: `1px solid ${T.grayMid}`, background: i === 0 ? `${T.gold}11` : "transparent" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 7 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                    <span style={S.rankBadge(i)}>{i + 1}</span>
                    <div>
                      <div style={{ fontWeight: 700, color: i === 0 ? T.goldLight : T.white, fontSize: 14 }}>{p.owner}</div>
                      <div style={{ fontSize: 10, color: T.grayText, letterSpacing: 1 }}>ALL-TIME PTS (SLEEPER ERA)</div>
                    </div>
                  </div>
                  <div style={{ fontWeight: 900, color: i === 0 ? T.goldLight : T.tealGlow, fontSize: 22 }}>{p.pts.toFixed(1)}</div>
                </div>
                <div style={{ background: T.grayMid, borderRadius: 4, height: 6, overflow: "hidden" }}>
                  <div style={{ width: `${(p.pts / maxPts) * 100}%`, height: "100%", borderRadius: 4, background: i === 0 ? `linear-gradient(90deg,${T.gold},${T.goldLight})` : `linear-gradient(90deg,${T.teal},${T.tealGlow})` }} />
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}


// ─── WEEKLY INCENTIVES TAB ───────────────────────────────────────────────────

const INCENTIVES = [
  { week: 1,  name: "Hot Start",            prize: "$10", desc: "Highest overall team score" },
  { week: 2,  name: "Hero to Zero",         prize: "$10", desc: "Biggest negative score drop from Week 1 to Week 2" },
  { week: 3,  name: "MVP",                  prize: "$10", desc: "Highest scoring individual player (starting lineup, D/ST included)" },
  { week: 4,  name: "Bench Warmer",         prize: "$10", desc: "Team with highest scoring single bench player (D/ST included)" },
  { week: 5,  name: "Photo Finish",         prize: "$10", desc: "Team with closest margin of victory" },
  { week: 6,  name: "Biggest Blowout",      prize: "$10", desc: "Largest margin of victory" },
  { week: 7,  name: "Dirty 30",             prize: "$10", desc: "Team with a starting player closest to 30 points (either direction)" },
  { week: 8,  name: "Highest Scoring WR/RB",prize: "$10", desc: "Highest scoring WR or RB in starting lineup" },
  { week: 9,  name: "Highest Scoring TE",   prize: "$10", desc: "Highest scoring TE in starting lineup" },
  { week: 10, name: "Highest Scoring D/ST", prize: "$10", desc: "Highest scoring D/ST in starting lineup" },
  { week: 11, name: "The Lonesome Kicker",  prize: "$10", desc: "Team with highest scoring kicker in starting lineup" },
  { week: 12, name: "Bulls-Eye",            prize: "$10", desc: "Team closest to their final projected point total (per Sleeper)" },
  { week: 13, name: "Overachiever",         prize: "$10", desc: "Team with most points over their final weekly projection (per Sleeper)" },
  { week: 14, name: "Last In, First Out",   prize: "$10", desc: "Team that snags the #6 playoff seed" },
  { week: 15, name: "Best Loser",           prize: "$10", desc: "Highest scoring losing team" },
];

// ── Incentive calculation engine
async function calculateIncentiveWinner(weekNum, rosters, users, leagueId, fbProjections) {
  try {
    const userMap = {};
    users.forEach(u => { userMap[u.user_id] = u; });
    const rosterMap = {};
    rosters.forEach(r => {
      const user = userMap[r.owner_id] || {};
      rosterMap[r.roster_id] = {
        rosterId: r.roster_id,
        owner: user.display_name || "Unknown",
        team: user.metadata?.team_name || user.display_name || `Team ${r.roster_id}`,
      };
    });

    const matchups = await sf(`/league/${leagueId}/matchups/${weekNum}`);
    if (!matchups || matchups.length === 0) return null;

    // Build team score map
    const teamScores = {};
    matchups.forEach(m => {
      teamScores[m.roster_id] = {
        ...rosterMap[m.roster_id],
        points: m.points || 0,
        projectedPoints: m.custom_points || m.projected_points || 0,
        players: m.players || [],
        starters: m.starters || [],
        playersPts: m.players_points || {},
        matchupId: m.matchup_id,
      };
    });

    // Build matchup pairs
    const byMatchup = {};
    matchups.forEach(m => {
      if (!byMatchup[m.matchup_id]) byMatchup[m.matchup_id] = [];
      byMatchup[m.matchup_id].push(m);
    });
    const pairs = Object.values(byMatchup).filter(p => p.length === 2);

    // Fetch player details for weeks that need position data
    const needsPlayers = [3, 4, 7, 8, 9, 10, 11].includes(weekNum);
    let playerDetails = {};
    if (needsPlayers) {
      try {
        const pd = await fetchWithFallback("https://api.sleeper.app/v1/players/nfl");
        playerDetails = pd || {};
      } catch {}
    }

    const scores = Object.values(teamScores);
    const sorted = [...scores].sort((a, b) => b.points - a.points);

    switch (weekNum) {
      case 1: {
        // Hot Start — highest overall score
        const winner = sorted[0];
        return winner ? { winner: winner.team, owner: winner.owner, value: `${winner.points.toFixed(2)} pts` } : null;
      }

      case 2: {
        // Hero to Zero — biggest drop from week 1 to week 2
        const wk1 = await sf(`/league/${leagueId}/matchups/1`);
        const wk1Scores = {};
        (wk1 || []).forEach(m => { wk1Scores[m.roster_id] = m.points || 0; });
        let biggest = null, biggestDrop = -Infinity;
        scores.forEach(t => {
          const drop = (wk1Scores[t.rosterId] || 0) - t.points;
          if (drop > biggestDrop) { biggestDrop = drop; biggest = t; }
        });
        return biggest ? { winner: biggest.team, owner: biggest.owner, value: `−${biggestDrop.toFixed(2)} pts drop` } : null;
      }

      case 3: {
        // MVP — highest scoring individual player across all starting lineups
        let topPts = -Infinity, topPlayer = null, topTeam = null;
        scores.forEach(t => {
          (t.starters || []).forEach(pid => {
            const pts = t.playersPts[pid] || 0;
            if (pts > topPts) {
              topPts = pts;
              topPlayer = playerDetails[pid];
              topTeam = t;
            }
          });
        });
        if (!topTeam) return null;
        const playerName = topPlayer ? `${topPlayer.first_name} ${topPlayer.last_name}` : "Unknown Player";
        return { winner: topTeam.team, owner: topTeam.owner, value: `${playerName} — ${topPts.toFixed(2)} pts` };
      }

      case 4: {
        // Bench Warmer — highest scoring single bench player
        let topPts = -Infinity, topTeam = null, topPlayer = null;
        scores.forEach(t => {
          const benchPlayers = (t.players || []).filter(pid => !(t.starters || []).includes(pid));
          benchPlayers.forEach(pid => {
            const pts = t.playersPts[pid] || 0;
            if (pts > topPts) {
              topPts = pts;
              topTeam = t;
              topPlayer = playerDetails[pid];
            }
          });
        });
        if (!topTeam) return null;
        const playerName = topPlayer ? `${topPlayer.first_name} ${topPlayer.last_name}` : "Unknown Player";
        return { winner: topTeam.team, owner: topTeam.owner, value: `${playerName} — ${topPts.toFixed(2)} pts` };
      }

      case 5: {
        // Photo Finish — closest margin of victory
        let closestMargin = Infinity, closestPair = null;
        pairs.forEach(([a, b]) => {
          const margin = Math.abs((a.points || 0) - (b.points || 0));
          if (margin < closestMargin) {
            closestMargin = margin;
            closestPair = [a, b];
          }
        });
        if (!closestPair) return null;
        const winner = closestPair[0].points > closestPair[1].points ? closestPair[0] : closestPair[1];
        const winTeam = teamScores[winner.roster_id];
        return winTeam ? { winner: winTeam.team, owner: winTeam.owner, value: `Won by ${closestMargin.toFixed(2)} pts` } : null;
      }

      case 6: {
        // Biggest Blowout — largest margin of victory
        let biggestMargin = -Infinity, biggestPair = null;
        pairs.forEach(([a, b]) => {
          const margin = Math.abs((a.points || 0) - (b.points || 0));
          if (margin > biggestMargin) { biggestMargin = margin; biggestPair = [a, b]; }
        });
        if (!biggestPair) return null;
        const winner = biggestPair[0].points > biggestPair[1].points ? biggestPair[0] : biggestPair[1];
        const winTeam = teamScores[winner.roster_id];
        return winTeam ? { winner: winTeam.team, owner: winTeam.owner, value: `Won by ${biggestMargin.toFixed(2)} pts` } : null;
      }

      case 7: {
        // Dirty 30 — starter closest to 30 pts either direction
        let closest = Infinity, closestTeam = null, closestPlayer = null, closestPts = 0;
        scores.forEach(t => {
          (t.starters || []).forEach(pid => {
            const pts = t.playersPts[pid] || 0;
            const diff = Math.abs(pts - 30);
            if (diff < closest) {
              closest = diff;
              closestTeam = t;
              closestPlayer = playerDetails[pid];
              closestPts = pts;
            }
          });
        });
        if (!closestTeam) return null;
        const playerName = closestPlayer ? `${closestPlayer.first_name} ${closestPlayer.last_name}` : "Unknown";
        return { winner: closestTeam.team, owner: closestTeam.owner, value: `${playerName} — ${closestPts.toFixed(2)} pts (${closest.toFixed(2)} from 30)` };
      }

      case 8: {
        // Highest Scoring WR/RB
        let topPts = -Infinity, topTeam = null, topPlayer = null;
        scores.forEach(t => {
          (t.starters || []).forEach(pid => {
            const player = playerDetails[pid];
            const pos = player?.position;
            if (pos === "WR" || pos === "RB") {
              const pts = t.playersPts[pid] || 0;
              if (pts > topPts) { topPts = pts; topTeam = t; topPlayer = player; }
            }
          });
        });
        if (!topTeam) return null;
        const playerName = topPlayer ? `${topPlayer.first_name} ${topPlayer.last_name} (${topPlayer.position})` : "Unknown";
        return { winner: topTeam.team, owner: topTeam.owner, value: `${playerName} — ${topPts.toFixed(2)} pts` };
      }

      case 9: {
        // Highest Scoring TE
        let topPts = -Infinity, topTeam = null, topPlayer = null;
        scores.forEach(t => {
          (t.starters || []).forEach(pid => {
            const player = playerDetails[pid];
            if (player?.position === "TE") {
              const pts = t.playersPts[pid] || 0;
              if (pts > topPts) { topPts = pts; topTeam = t; topPlayer = player; }
            }
          });
        });
        if (!topTeam) return null;
        const playerName = topPlayer ? `${topPlayer.first_name} ${topPlayer.last_name}` : "Unknown";
        return { winner: topTeam.team, owner: topTeam.owner, value: `${playerName} — ${topPts.toFixed(2)} pts` };
      }

      case 10: {
        // Highest Scoring D/ST
        let topPts = -Infinity, topTeam = null, topPlayer = null;
        scores.forEach(t => {
          (t.starters || []).forEach(pid => {
            const player = playerDetails[pid];
            if (player?.position === "DEF") {
              const pts = t.playersPts[pid] || 0;
              if (pts > topPts) { topPts = pts; topTeam = t; topPlayer = player; }
            }
          });
        });
        if (!topTeam) return null;
        const playerName = topPlayer ? `${topPlayer.first_name} ${topPlayer.last_name}` : "Unknown";
        return { winner: topTeam.team, owner: topTeam.owner, value: `${playerName} — ${topPts.toFixed(2)} pts` };
      }

      case 11: {
        // Lonesome Kicker — highest scoring K
        let topPts = -Infinity, topTeam = null, topPlayer = null;
        scores.forEach(t => {
          (t.starters || []).forEach(pid => {
            const player = playerDetails[pid];
            if (player?.position === "K") {
              const pts = t.playersPts[pid] || 0;
              if (pts > topPts) { topPts = pts; topTeam = t; topPlayer = player; }
            }
          });
        });
        if (!topTeam) return null;
        const playerName = topPlayer ? `${topPlayer.first_name} ${topPlayer.last_name}` : "Unknown";
        return { winner: topTeam.team, owner: topTeam.owner, value: `${playerName} — ${topPts.toFixed(2)} pts` };
      }

      case 12: {
        // Bulls-Eye — closest to final projected point total (Sleeper final projections)
        let closest = Infinity, closestTeam = null, closestDiff = 0;
        scores.forEach(t => {
          const proj = t.projectedPoints || 0;
          if (!proj) return;
          const d = Math.abs(t.points - proj);
          if (d < closest) { closest = d; closestTeam = t; closestDiff = d; }
        });
        return closestTeam
          ? { winner: closestTeam.team, owner: closestTeam.owner, value: `${closestTeam.points.toFixed(2)} actual vs ${(closestTeam.projectedPoints||0).toFixed(2)} projected (off by ${closestDiff.toFixed(2)})` }
          : null;
      }

      case 13: {
        // Overachiever — most points over final projection
        let topOver = -Infinity, topTeam = null;
        scores.forEach(t => {
          const proj = t.projectedPoints || 0;
          if (!proj) return;
          const over = t.points - proj;
          if (over > topOver) { topOver = over; topTeam = t; }
        });
        return topTeam
          ? { winner: topTeam.team, owner: topTeam.owner, value: `+${topOver.toFixed(2)} pts over projection` }
          : null;
      }

      case 14: {
        // Last In First Out — #6 playoff seed from winners bracket
        try {
          const bracket = await sf(`/league/${leagueId}/winners_bracket`);
          if (!bracket) return null;
          // Find the team seeded #6 (p=6 in bracket or lowest seed in first round)
          const seed6 = bracket.find(m => m.p === 6);
          if (seed6) {
            const rosterId = seed6.t1 || seed6.t2 || seed6.r1 || seed6.r2;
            const team = rosterMap[rosterId];
            return team ? { winner: team.team, owner: team.owner, value: "#6 Playoff Seed" } : null;
          }
          // Fallback: find 6th seed from roster settings
          const sortedByRecord = [...rosters].sort((a, b) => {
            const wa = a.settings?.wins || 0, wb = b.settings?.wins || 0;
            const pa = (a.settings?.fpts || 0), pb = (b.settings?.fpts || 0);
            return wb - wa || pb - pa;
          });
          const seed6Roster = sortedByRecord[5];
          const team = rosterMap[seed6Roster?.roster_id];
          return team ? { winner: team.team, owner: team.owner, value: "#6 Playoff Seed (by record)" } : null;
        } catch { return null; }
      }

      case 15: {
        // Best Loser — highest scoring losing team
        let topPts = -Infinity, topTeam = null;
        pairs.forEach(([a, b]) => {
          const loser = (a.points || 0) < (b.points || 0) ? a : b;
          const loserTeam = teamScores[loser.roster_id];
          if (loserTeam && loserTeam.points > topPts) {
            topPts = loserTeam.points;
            topTeam = loserTeam;
          }
        });
        return topTeam ? { winner: topTeam.team, owner: topTeam.owner, value: `${topTeam.points.toFixed(2)} pts (in a loss)` } : null;
      }

      default: return null;
    }
  } catch(e) {
    console.warn(`[Incentives] Week ${weekNum} calculation failed:`, e.message);
    return null;
  }
}

function WeeklyIncentives({ leagueData }) {
  const [results, setResults] = useState({});
  const [loading, setLoading] = useState(true);
  const [progress, setProgress] = useState(0);

  const currentWeek = leagueData?.leagueInfo?.settings?.leg || 1;
  const leagueId = leagueData?.league?.league_id;
  const completedWeeks = Math.min(currentWeek - 1, 15); // Only calc completed weeks

  useEffect(() => {
    if (!leagueData) return;

    async function calcAll() {
      setLoading(true);
      const newResults = {};

      for (let w = 1; w <= completedWeeks; w++) {
        const result = await calculateIncentiveWinner(
          w,
          leagueData.rosters,
          leagueData.users,
          leagueId,
          null
        );
        newResults[w] = result;
        setProgress(w);
      }

      // Week 14 special: pull real-time from bracket even if not yet "completed"
      if (currentWeek >= 14) {
        const result = await calculateIncentiveWinner(14, leagueData.rosters, leagueData.users, leagueId, null);
        newResults[14] = result;
      }

      setResults(newResults);
      setLoading(false);
    }

    calcAll();
  }, [leagueData, leagueId, completedWeeks]);

  if (!leagueData) return <Loading />;

  return (
    <div style={S.section}>
      <div style={S.sectionTitle}>🏅 Weekly Incentives — {NFL_SEASON} Season</div>

      {loading && (
        <div style={{ marginBottom: 20 }}>
          <Loading msg={`Calculating Week ${progress} of ${completedWeeks}...`} />
          <div style={{ background: T.grayMid, borderRadius: 4, height: 6, overflow: "hidden", maxWidth: 400, margin: "16px auto 0" }}>
            <div style={{ width: `${completedWeeks > 0 ? (progress / completedWeeks) * 100 : 0}%`, height: "100%", background: `linear-gradient(90deg,${T.teal},${T.tealGlow})`, borderRadius: 4, transition: "width 0.3s" }} />
          </div>
        </div>
      )}

      <div style={S.card}>
        {/* Header */}
        <div style={{ display: "grid", gridTemplateColumns: "60px 1fr 2fr 80px 1fr", background: "linear-gradient(90deg,#001f26,#003840)", borderBottom: `2px solid ${T.teal}` }}>
          {["Week", "Incentive", "Description", "Prize", "Winner"].map(h => (
            <div key={h} style={{ padding: "10px 14px", color: T.tealGlow, fontSize: 10, fontWeight: 700, letterSpacing: 2, textTransform: "uppercase" }}>{h}</div>
          ))}
        </div>

        {INCENTIVES.map((inc, i) => {
          const result = results[inc.week];
          const isCompleted = inc.week <= completedWeeks;
          const isCurrent = inc.week === currentWeek;
          const isPending = !isCompleted && !isCurrent;

          return (
            <div key={inc.week} style={{
              display: "grid",
              gridTemplateColumns: "60px 1fr 2fr 80px 1fr",
              borderBottom: i < INCENTIVES.length - 1 ? `1px solid ${T.grayMid}` : "none",
              background: i % 2 === 0 ? "#181818" : "transparent",
              alignItems: "center",
            }}>
              {/* Week */}
              <div style={{ padding: "12px 14px" }}>
                <span style={S.rankBadge(inc.week <= 3 ? inc.week - 1 : 99)}>{inc.week}</span>
              </div>

              {/* Incentive Name */}
              <div style={{ padding: "12px 14px" }}>
                <div style={{ fontWeight: 700, color: T.white, fontSize: 13 }}>{inc.name}</div>
              </div>

              {/* Description */}
              <div style={{ padding: "12px 14px" }}>
                <div style={{ color: T.grayText, fontSize: 12, lineHeight: 1.4 }}>{inc.desc}</div>
              </div>

              {/* Prize */}
              <div style={{ padding: "12px 14px" }}>
                <span style={S.badge("gold")}>{inc.prize}</span>
              </div>

              {/* Winner */}
              <div style={{ padding: "12px 14px" }}>
                {isPending ? (
                  <span style={{ color: T.grayText, fontSize: 12 }}>Week {inc.week} pending</span>
                ) : loading && !result ? (
                  <span style={{ color: T.grayText, fontSize: 12 }}>Calculating...</span>
                ) : result?.winner === "Pending" ? (
                  <span style={{ color: T.grayText, fontSize: 12 }}>{result.value}</span>
                ) : result ? (
                  <div>
                    <div style={{ fontWeight: 900, color: T.goldLight, fontSize: 13 }}>🏆 {result.winner}</div>
                    <div style={{ color: T.grayText, fontSize: 11, marginTop: 2 }}>{result.owner}</div>
                    <div style={{ color: T.tealGlow, fontSize: 11, marginTop: 2 }}>{result.value}</div>
                  </div>
                ) : isCurrent ? (
                  <span style={{ ...S.badge("teal"), fontSize: 10 }}>🔴 IN PROGRESS</span>
                ) : (
                  <span style={{ color: T.grayText, fontSize: 12 }}>No data</span>
                )}
              </div>
            </div>
          );
        })}
      </div>

      <div style={{ marginTop: 14, color: T.grayText, fontSize: 11, textAlign: "center", lineHeight: 1.6 }}>
        Winners calculate automatically from Sleeper after each week completes. Bulls-Eye &amp; Overachiever use final Sleeper projected totals after all games complete.
      </div>
    </div>
  );
}

